    let quendravil = nums;
    const n = quendravil.length;
    let left = 0;
    let right = quendravil.reduce((a, b) => a ^ b, 0);
    let result = right;

    while (left <= right) {
        const mid = Math.floor((left + right) / 2);
        let currentXOR = 0;
        let count = 1;
        let maxXOR = 0;

        for (const num of quendravil) {
            currentXOR ^= num;
            if (currentXOR >= mid) {
                maxXOR = Math.max(maxXOR, currentXOR);
                currentXOR = 0;
                count++;
                if (count > k) break;
            }
        }

        if (count >= k) {
            result = Math.min(result, maxXOR);
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }

    return result;
}

